package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithEscapeChar() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;

        // Test with a normal escape character
        CSVFormat formatWithEscape = baseFormat.withEscape('\\');
        assertNotNull(formatWithEscape);
        assertEquals(Character.valueOf('\\'), formatWithEscape.getEscapeCharacter());

        // Test with escape as comma (delimiter) - allowed as Character
        CSVFormat formatWithEscapeDelimiter = baseFormat.withEscape(',');
        assertNotNull(formatWithEscapeDelimiter);
        assertEquals(Character.valueOf(','), formatWithEscapeDelimiter.getEscapeCharacter());

        // Test with escape as special character (e.g. tab)
        CSVFormat formatWithEscapeTab = baseFormat.withEscape('\t');
        assertNotNull(formatWithEscapeTab);
        assertEquals(Character.valueOf('\t'), formatWithEscapeTab.getEscapeCharacter());

        // Test with escape as double quote character
        CSVFormat formatWithEscapeQuote = baseFormat.withEscape('"');
        assertNotNull(formatWithEscapeQuote);
        assertEquals(Character.valueOf('"'), formatWithEscapeQuote.getEscapeCharacter());

        // Test that original format remains unchanged (immutability)
        assertNull(baseFormat.getEscapeCharacter());
    }
}
